// ===============================
// 1. Coletar e filtrar linhas válidas
// ===============================

const validRows = items
  .map(item => item.json)
  .filter(row =>
    row.chat_id &&
    row.text &&
    row.processed === "false"
  );

// Se não houver mensagens válidas, encerra
if (validRows.length === 0) {
  return [];
}

// ===============================
// 2. Agrupar por chat_id
// ===============================

const groups = {};

for (const row of validRows) {
  const chatId = row.chat_id;

  if (!groups[chatId]) {
    groups[chatId] = {
      chat_id: chatId,
      group_title: row.group_title || `Grupo ${chatId}`,
      messages: []
    };
  }

  groups[chatId].messages.push(row);
}

// ===============================
// 3. Ordenar mensagens por data
// ===============================

for (const chatId in groups) {
  groups[chatId].messages.sort(
    (a, b) => new Date(a.createdAt) - new Date(b.createdAt)
  );
}

// ===============================
// 4. Construir combined_text (COM nome do grupo)
// ===============================

const output = Object.values(groups).map(group => {
  const formattedMessages = group.messages.map(row => {
    const time = new Date(row.createdAt)
      .toISOString()
      .substring(11, 16);

    const author =
      row.user_name ||
      (row.username ? `@${row.username}` : `Usuário ${row.user_id}`);

    return `[${time}] ${author}: ${row.text}`;
  });

  const combinedText = `
Grupo: ${group.group_title}

Mensagens (ordem cronológica):
${formattedMessages.join("\n")}
`.trim();

  return {
    json: {
      chat_id: group.chat_id,
      group_title: group.group_title,
      message_count: formattedMessages.length,
      combined_text: combinedText
    }
  };
});

// ===============================
// 5. Retorno
// ===============================

return output;

// Lista de pessoas que devem receber o resumo/alerta
const RECIPIENTS = [
  { id: "998531040", role: "Simone" },
  { id: "8319488518", role: "Mayara" }
];

const output = [];

for (const item of items) {
  const data = item.json;
  for (const user of RECIPIENTS) {
    output.push({ json: { ...data, chat_id: user.id, recipient_role: user.role } });
  }
}

return output;

return items.map(item => ({
  json: {
    meta: {
      chat_id: item.json.chat_id,
      group_title: item.json.group_title
    },
    content: item.json.combined_text
  }
}));

function escapeMarkdown(text) {
  return text.replace(/[_*[\]()~`>#+\-=|{}.!]/g, '\\$&');
}

return items.map(item => {
  item.json.safeText = escapeMarkdown(item.json.output);
  return item;
});
